function LFightBoutData:InitPbBoutData(pb,lifeState)


	self._aid = pb.aId --当前回合出手主体
	self._skill = pb.skill --释放的技能Id


    local tbl = {}
    local actions = pb.actions or {}
    for k,v in ipairs(actions) do
        local tb2 = {}
        for q, w in ipairs(v.list) do
            local actionData = LFightBoutActionData:New()
            actionData:InitPbBoutActionData(w,lifeState)

            table.insert(tb2,actionData)
        end
        table.insert(tbl,tb2)
    end

	self._actionDataList = tbl
	self._totalAction = #self._actionDataList

end

function LFightBoutData:InitJsonBoutData(json)
	self._aid = json.aId --当前回合出手主体
	self._skill = json.skill --释放的技能Id
	self._actionDataList = self:ParseActionData(json.actions or {})
	self._totalAction = #self._actionDataList
end

function LFightBoutData:ParseActionData(actions)
	local tbl = {}
	for k,v in ipairs(actions) do
		local tb2 = {}
		for q, w in ipairs(v) do
			local actionData = LFightBoutActionData:New()
			actionData:InitJsonBoutActionData(w)
			table.insert(tb2,actionData)
		end
		table.insert(tbl,tb2)
	end
	return tbl
end

function LFightBoutData:GetAttackId()
	return self._aid
end

function LFightBoutData:GetSkill()
	return self._skill
end

