function LFightBoutData:GetActionDataList()
	return self._actionDataList
end

function LFightBoutData:GetActionDataByIndex(index)
	return self._actionDataList[index]
end

function LFightBoutData:GetTotalAction()
	return self._totalAction
end


function LFightBoutData:ChangeToNextActions()
	local nextActionList,curIndex = self:GetNextActions()
	if self._actionDataList[curIndex] then
		self._curActionIndex = curIndex
	end
	return nextActionList,curIndex
end

function LFightBoutData:GetNextActions()
	local curIndex = self._curActionIndex
	if not curIndex then
		curIndex = 1
	else
		curIndex = curIndex + 1
	end

	local nextActionList = self._actionDataList[curIndex]
	return nextActionList,curIndex
end

